    {
      "sentence": "Elle ___ une tablette.",
      "wordBank": ["a", "as", "ont", "sont"],
      "correctAnswer": "a",
      "explanation": "'A' ist die korrekte Form des Verbs 'avoir' für die dritte Person Singular (sie). Die anderen Wörter sind entweder falsche Personen oder Verben."
    },
    {
      "sentence": "Nous ___ un ordinateur.",
      "wordBank": ["avons", "ont", "a", "sommes"],
      "correctAnswer": "avons",
      "explanation": "'Avons' ist die korrekte Form von 'avoir' für die erste Person Plural (wir). Die anderen Wörter sind entweder falsche Verben oder passen nicht zur Person."
    },
    {
      "sentence": "Tu ___ une caméra.",
      "wordBank": ["as", "a", "es", "suis"],
      "correctAnswer": "as",
      "explanation": "'As' ist die korrekte Form von 'avoir' für die zweite Person Singular (du). Es handelt sich um ein einfaches Präsens-Verb, das A1-Lernende kennen müssen."
    },
    {
      "sentence": "Ils ___ des écouteurs.",
      "wordBank": ["ont", "a", "sont", "aiment"],
      "correctAnswer": "ont",
      "explanation": "'Ont' ist die korrekte Form von 'avoir' für die dritte Person Plural (sie). Die anderen Wörter sind entweder falsche Verben oder passen nicht zur Aussage."
    }
